<unsafe_rust_function>
#[no_mangle]
pub unsafe extern "C" fn abc_error(mut fmt: *mut core::ffi::c_char, mut args: ...) {
    let mut ap: ::core::ffi::VaListImpl;
    ap = args.clone();
    fprintf(
        stderr,
        b"error in input file %s: line no. %d - \0" as *const u8
            as *const core::ffi::c_char,
        abc_file.as_mut_ptr(),
        input_line,
    );
    vfprintf(stderr, fmt, ap.as_va_list());
    fprintf(stderr, b"\n\0" as *const u8 as *const core::ffi::c_char);
    exit(1 as core::ffi::c_int);
}
</unsafe_rust_function>

