pub unsafe extern "C" fn set_dnl(mut dnl_str: *mut core::ffi::c_char) {
    while *dnl_str as core::ffi::c_int == ' ' as i32 {
        dnl_str = dnl_str.offset(1);
    }
    if strncmp(dnl_str, b"1/4\0" as *const u8 as *const core::ffi::c_char, 3 as size_t)
        == 0 as core::ffi::c_int
    {
        dnl = CROTCHET;
    } else if strncmp(
        dnl_str,
        b"1/8\0" as *const u8 as *const core::ffi::c_char,
        3 as size_t,
    ) == 0 as core::ffi::c_int
    {
        dnl = QUAVER;
    } else if strncmp(
        dnl_str,
        b"1/16\0" as *const u8 as *const core::ffi::c_char,
        3 as size_t,
    ) == 0 as core::ffi::c_int
    {
        dnl = SEMIQUAVER;
    } else if strncmp(
        dnl_str,
        b"1/32\0" as *const u8 as *const core::ffi::c_char,
        4 as size_t,
    ) == 0 as core::ffi::c_int
    {
        dnl = DEMISEMIQUAVER;
    } else {
        printf(
            b"default note length not recognised\n\0" as *const u8
                as *const core::ffi::c_char,
        );
        dnl = QUAVER;
    };
}
