pub unsafe extern "C" fn get_dnl(mut entry: *mut Record) {
    let mut meter: [core::ffi::c_char; 99] = [0; 99];
    let mut meter_field: Field = Field {
        string: 0 as *mut core::ffi::c_char,
        info1: 0,
        info2: 0,
