{
	int	new_line = 1;
	int	f = 0;
	int	i = 0;
	static	char	index[999];

	while (fmt[f]) {
		if (new_line == 1) {
			if ((fgets(index,999,In)) == NULL)
				return(0);
			new_line = 0;
		}
		if (strchr("FXJORCTMLK",fmt[f]))
